{{include reference="GuidedTour.Code.Macros" /}}

{{velocity ouptput="false"}}
##set ($discard = $xwiki.ssx.use('GuidedTour.Code.TaskClassSheet'))
#set ($discard = $xwiki.jsx.use('GuidedTour.Code.TourClassSheet'))
#set ($isEdit = $xcontext.action == 'edit')
#set ($tour = $doc.getObject('XWiki.GuidedTour.TourClass'))
{{/velocity}}

{{velocity}}
{{html wiki='true'}}
  #addTaskModal($doc.getDocumentReference)
  #deleteTaskModal()
  <div class="taskSpecificProps">
    <dl id="guidedtour-task-props">
    #set($xclass = $tour.xWikiClass)
    #foreach($property in $xclass.properties)
      #set ($propertyId = "${xclass.name}_${tour.number}_$property.name")
      <dt>
        <label for="$!escapetool.xml($propertyId)">$escapetool.xml($property.translatedPrettyName)</label>
        <span class="xHint">$!escapetool.xml($property.hint)</span>
      </dt>
      <dd>
        $doc.display($property.name, $tour)
      </dd>
    #end
    </dl>
  </div>

  <h2>Tasks</h2>

  #if ($isEdit)
    <a href="#addTaskFormModal" data-toggle="modal" data-target="#addTaskFormModal" class="btn btn-primary">Add Task</a>
  #end

  #set ($liveDataConfig = {
    "meta": {
        "propertyDescriptors": [
          { "id": "order", "displayer": "text", "filterable": false, "sortable": false },
          { "id": "title", "displayer": "html", "filterable": true, "sortable": false },
          { "id": "steps", "displayer": "text", "filterable": false, "sortable": false },
          { 'id': 'actions', 'displayer': 'html', 'filterable': false, 'sortable': false}
        ],
        'entryDescriptor': {
          'idProperty': 'order'
        }
      }
  })
  #set ($sourceParameters = $escapetool.url({
    'resultPage': 'GuidedTour.Code.TaskJson',
    'tourId': "${doc.getDocumentReference()}"
  }))


  {{liveData
    id='tourTasksList'
    properties="order,title,steps,actions"
    source='liveTable'
    sourceParameters="$sourceParameters"
  }}$jsontool.serialize($liveDataConfig){{/liveData}}
{{/html}}
{{/velocity}}

property.code:
require(['jquery', 'xwiki-meta'], function($, xm) {
  const deleteTask = function(relatedTarget) {
    const taskName = $(relatedTarget).data('taskname');
    const modal = $(document).find('#confirmDeleteTaskModal');
    const confirmBtn = modal.find('.btn-danger');
    const targetUrl = $(relatedTarget).attr('href');
    var notification;
    $.ajax({
      url: targetUrl,
      type: 'DELETE',
      beforeSend: function(xhr) {
        confirmBtn.prop('disabled', true);
        notification = new XWiki.widgets.Notification('Removing task and all its steps...', 'inprogress');
      },
      success: function() {
        confirmBtn.prop('disabled', false);
        modal.modal('hide');
        notification.replace(new XWiki.widgets.Notification('Task successfully removed!', 'done'));
        $('#tourTasksList').data('liveData').updateEntries();
      },
      error: function() {
        confirmBtn.prop('disabled', false);
        modal.modal('hide');
        notification.replace(new XWiki.widgets.Notification('There was an error while attempting to remove the task!', 'error'));
      }
    });
  }

  $(document).on('click', '#confirmDeleteTaskModal .btn.btn-danger', function() {
    var relatedTarget = $('#confirmDeleteTaskModal').data('relatedTarget');
    deleteTask(relatedTarget);
  });

  $(document).on('click', '.task-delete-action', function (event) {
    event.preventDefault();
    const taskName = $(this).data('taskname');
    var modalDescription = `You are about to delete task <${taskName}> and all associated steps!`
    var modal = $(document).find('#confirmDeleteTaskModal');
    $(modal).find('.modal-body').text(modalDescription);
    modal.data('relatedTarget', event.currentTarget);
    modal.modal('show');
  });

  const getTaskUrl = function(taskId) {
    const parentReference = XWiki.Model.resolve(xm.document, XWiki.EntityType.DOCUMENT).parent;
    const taskReference = XWiki.Model.resolve(taskId, XWiki.EntityType.DOCUMENT, parentReference);
    return new XWiki.Document(taskReference).getURL('view');
  }
  const getTaskDependencies = function() {
    var dependsOn = [];
    var treeElement = $('#taskTreeContainer').find('.xtree');
    if (treeElement.length > 0) {
      var treeInstance = $.jstree.reference(treeElement);
      if (treeInstance) {
        var checkedIds = treeInstance.get_checked() || [];
        $.each(checkedIds, function(index, fullId) {
          var parts = fullId.split('.');
          var pageName = parts[parts.length - 1];
          dependsOn.push(pageName);
        });
      }
    }
    return dependsOn;
  }
  $(document).on('click', '#addTaskFormModal .btn.btn-primary', function (event) {
    event.preventDefault();
    const form = $('#add-tasks-form');
    var confirmBtn = $(this);
    var modal = $('#addTaskFormModal');
    var dependsOn = getTaskDependencies();
    var formData = {
      title: $('#taskTitle').val(),
      dependsOn: dependsOn
    };
    var notification;
    $.ajax({
      url: form.attr('target'),
      type: 'POST',
      contentType: 'application/json',
      data: JSON.stringify(formData),
      beforeSend: function() {
        confirmBtn.prop('disabled', true);
        notification = new XWiki.widgets.Notification('Creating new task...', 'inprogress');
      },
      success: function(taskId) {
        form.trigger('reset');
        notification.replace(new XWiki.widgets.Notification('Task successfully created!', 'done'));
        $('#tourTasksList').data('liveData').updateEntries();
        setTimeout(function() {
          window.location.href = getTaskUrl(taskId);
        }, 500);
      },
      error: function(response) {
        notification.replace(new XWiki.widgets.Notification('Failed to create task: ' + response.statusText, 'error'));
      },
      complete: function() {
        confirmBtn.prop('disabled', false);
        modal.modal('hide');
      }
    });
  });
});
